#include <vector>
#include <algorithm>
using namespace std;
int main(){
    int n; cin>>n;
    vector<int> h(n);
    for(int i=0;i<n;i++) cin>>h[i];
    int l=0,r=n-1,maxL=0,maxR=0,water=0;
    while(l<r){
        if(h[l]<h[r]){
            if(h[l]>=maxL) maxL=h[l];
            else water+=maxL-h[l];
            l++;
        } else {
            if(h[r]>=maxR) maxR=h[r];
            else water+=maxR-h[r];
            r--;
        }
    }
    cout<<water<<endl;
    return 0;
}

